import{_ as e,I as a,c as o,o as b,a5 as r,j as d,J as i,aw as n}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"常用快捷键推荐","description":"精选 15 个最实用的快捷键，让你的日常操作效率翻倍。","frontmatter":{"title":"常用快捷键推荐","subtitle":"15 个让你效率翻倍的快捷键","course":"OpenCode 中文实战课","stage":"第二阶段","lesson":"2.3","duration":"8 分钟","practice":"10 分钟","level":"新手","description":"精选 15 个最实用的快捷键，让你的日常操作效率翻倍。","tags":["快捷键","效率","日常使用"],"prerequisite":["2.1 界面与操作"]},"headers":[],"relativePath":"2-daily/03-shortcuts.md","filePath":"2-daily/03-shortcuts.md","lastUpdated":1772014034000}'),s={name:"2-daily/03-shortcuts.md"};function k(h,t,c,p,g,u){const l=a("AdInArticle");return b(),o("div",null,[t[0]||(t[0]=r('<h1 id="常用快捷键推荐" tabindex="-1">常用快捷键推荐 <a class="header-anchor" href="#常用快捷键推荐" aria-label="Permalink to “常用快捷键推荐”">​</a></h1><blockquote><p>💡 <strong>一句话总结</strong>：记住这 15 个快捷键，日常操作效率翻倍。</p></blockquote><h2 id="📝-课程笔记" tabindex="-1">📝 课程笔记 <a class="header-anchor" href="#📝-课程笔记" aria-label="Permalink to “📝 课程笔记”">​</a></h2><p>本课核心知识点整理：</p><p><img src="'+n+'" alt="常用快捷键推荐学霸笔记" data-zoom-src="/images/2-daily/03-shortcuts-notes.jpeg"></p><hr><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to “学完你能做什么”">​</a></h2><ul><li>用快捷键快速新建/切换会话</li><li>一键切换模型和 Agent</li><li>快速撤销、重做、复制消息</li><li>用翻页键浏览长对话</li></ul><hr><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to “你现在的困境”">​</a></h2><ul><li>每次新建会话都要打 <code>/new</code></li><li>切换模型要输入 <code>/models</code></li><li>想撤销操作不知道怎么做</li><li>长对话只能慢慢滚动</li></ul><hr><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to “什么时候用这一招”">​</a></h2><ul><li>当你需要：频繁在 OpenCode 中工作</li><li>而且不想：每次都打命令</li></ul><hr><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to “🎒 开始前的准备”">​</a></h2><blockquote><p>确保你已经完成以下事项：</p></blockquote><ul><li>[ ] 完成了 <a href="./01-interface.html">2.1 界面与操作</a></li><li>[ ] 能正常和 AI 对话</li></ul><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to “核心思路”">​</a></h2><h3 id="leader-键机制-重要" tabindex="-1">Leader 键机制（重要！） <a class="header-anchor" href="#leader-键机制-重要" aria-label="Permalink to “Leader 键机制（重要！）”">​</a></h3><p>OpenCode 使用 <strong>Leader 键</strong>（默认 <kbd>Ctrl</kbd>+<kbd>X</kbd>）作为快捷键前缀，避免与终端快捷键冲突。</p><div class="info custom-block"><p class="custom-block-title">🤔 什么是 Leader 键？</p><p>Leader 键类似于 Vim 的 <code>&lt;Leader&gt;</code> 或游戏里的&quot;组合键&quot;。它不是一个功能键，而是一个<strong>前缀键</strong>。</p><p>按下 Leader 键后，OpenCode 会等待你按下一个字母，两者组合起来才是一个完整的快捷键。</p></div><p><strong>操作方式（三步法）</strong>：</p>',24)),t[1]||(t[1]=d("div",{class:"language-"},[d("button",{title:"Copy Code",class:"copy"}),d("span",{class:"lang"}),d("pre",null,[d("code",{"v-pre":""},`┌─────────────────────────────────────────────────────────────┐
│  第 1 步          第 2 步          第 3 步                   │
│  按下 Ctrl+X  →   松开所有键   →   按下字母键（如 N）        │
│                                                             │
│  ⚠️ 关键：第 2 步必须松开！不是同时按住三个键！              │
└─────────────────────────────────────────────────────────────┘`)])],-1)),t[2]||(t[2]=r('<p><strong>举例说明</strong>：</p><table tabindex="0"><thead><tr><th>你想做什么</th><th>完整操作</th><th>错误操作</th></tr></thead><tbody><tr><td>新建会话</td><td>按 Ctrl+X → 松开 → 按 N</td><td>❌ 同时按 Ctrl+X+N</td></tr><tr><td>打开会话列表</td><td>按 Ctrl+X → 松开 → 按 L</td><td>❌ 按住 Ctrl 不放按 X 再按 L</td></tr><tr><td>切换模型</td><td>按 Ctrl+X → 松开 → 按 M</td><td>❌ 按太快没松开</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">💡 练习技巧</p><p>刚开始可以<strong>刻意放慢</strong>：按 Ctrl+X 后，心里默数&quot;1&quot;，再按字母键。熟练后自然会快起来。</p></div><h3 id="本课精选标准" tabindex="-1">本课精选标准 <a class="header-anchor" href="#本课精选标准" aria-label="Permalink to “本课精选标准”">​</a></h3><p>从 60+ 个快捷键中，按以下标准精选：</p><ol><li><strong>高频使用</strong> - 几乎每天都会用</li><li><strong>节省时间</strong> - 比打命令快很多</li><li><strong>容易记忆</strong> - 有规律可循</li></ol><hr><h2 id="精选-15-个快捷键" tabindex="-1">精选 15 个快捷键 <a class="header-anchor" href="#精选-15-个快捷键" aria-label="Permalink to “精选 15 个快捷键”">​</a></h2>',8)),i(l),t[3]||(t[3]=r('<h3 id="🔥-第一梯队-每天必用" tabindex="-1">🔥 第一梯队：每天必用 <a class="header-anchor" href="#🔥-第一梯队-每天必用" aria-label="Permalink to “🔥 第一梯队：每天必用”">​</a></h3><p>这 8 个是最高频的，优先记住：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th><th>说明</th></tr></thead><tbody><tr><td><kbd>Enter</kbd></td><td>发送消息</td><td>回车发送</td></tr><tr><td><kbd>Shift</kbd>+<kbd>Enter</kbd></td><td><strong>换行（不发送）</strong></td><td>写多行提示词时用</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>C</kbd></td><td>清空输入 / 关闭对话框 / 退出</td><td>详见下方说明</td></tr><tr><td><kbd>Escape</kbd></td><td>中断 AI 响应</td><td>AI 在生成时按，立即停止。<strong>按两次可强制中断</strong></td></tr><tr><td><kbd>↑</kbd> / <kbd>↓</kbd></td><td>翻阅历史输入</td><td><strong>输入框为空时</strong>，按上下键可找回之前发过的消息</td></tr><tr><td><kbd>Tab</kbd></td><td>切换 Agent</td><td>在 Plan/Build/不同 Agent 间切换</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>N</kbd></td><td>新建会话</td><td>Leader 键 + N = <strong>N</strong>ew</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>L</kbd></td><td>会话列表</td><td>Leader 键 + L = <strong>L</strong>ist</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">💡 换行的多种方式</p><p>除了 <kbd>Shift</kbd>+<kbd>Enter</kbd>，还可以用：</p><ul><li><kbd>Ctrl</kbd>+<kbd>Enter</kbd></li><li><kbd>Alt</kbd>+<kbd>Enter</kbd></li><li><kbd>Ctrl</kbd>+<kbd>J</kbd></li></ul><p>选一个顺手的记住就行。</p></div><details class="details custom-block"><summary>📦 Ctrl+C 的三种行为（v1.1.58 更新）</summary><ul><li><strong>有弹出对话框时</strong>：关闭对话框（如确认框、选择框等）</li><li><strong>输入框有内容时</strong>：清空输入框（不退出）</li><li><strong>输入框为空时</strong>：退出 OpenCode</li></ul><p>⚠️ 注意：虽然 Ctrl+C 和 Ctrl+D 都能退出，但行为略有不同。Ctrl+D 是直接退出信号，Ctrl+C 则先尝试清空输入。这和终端的行为一致，程序员会很熟悉。</p></details><h3 id="⚡-第二梯队-效率提升" tabindex="-1">⚡ 第二梯队：效率提升 <a class="header-anchor" href="#⚡-第二梯队-效率提升" aria-label="Permalink to “⚡ 第二梯队：效率提升”">​</a></h3><p>这 5 个能显著提升效率：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th><th>记忆技巧</th></tr></thead><tbody><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>M</kbd></td><td>模型列表</td><td><strong>M</strong>odel</td></tr><tr><td><kbd>F2</kbd></td><td>快速切换最近模型</td><td>IDE 通用</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>U</kbd></td><td>撤销消息</td><td><strong>U</strong>ndo</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>R</kbd></td><td>重做消息</td><td><strong>R</strong>edo</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>P</kbd></td><td>命令面板</td><td>同 VS Code</td></tr></tbody></table><h3 id="🎯-第三梯队-锦上添花" tabindex="-1">🎯 第三梯队：锦上添花 <a class="header-anchor" href="#🎯-第三梯队-锦上添花" aria-label="Permalink to “🎯 第三梯队：锦上添花”">​</a></h3><p>这 5 个在特定场景很有用：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th><th>使用场景</th></tr></thead><tbody><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>Y</kbd></td><td>复制消息</td><td>复制 AI 回复</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>C</kbd></td><td>压缩上下文</td><td>对话太长时</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>B</kbd></td><td>切换侧边栏</td><td>看会话树</td></tr><tr><td><kbd>PageUp</kbd> / <kbd>PageDown</kbd></td><td>翻页浏览</td><td>长对话翻阅</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>T</kbd></td><td>主题列表</td><td>换个心情</td></tr></tbody></table><h3 id="🧑‍💻-程序员专属-输入框快捷键" tabindex="-1">🧑‍💻 程序员专属：输入框快捷键 <a class="header-anchor" href="#🧑‍💻-程序员专属-输入框快捷键" aria-label="Permalink to “🧑‍💻 程序员专属：输入框快捷键”">​</a></h3><p>如果你用过终端或 Emacs，这些你会很熟悉：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th><th>Readline 风格</th></tr></thead><tbody><tr><td><kbd>Ctrl</kbd>+<kbd>A</kbd></td><td>跳到行首</td><td>✅</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>E</kbd></td><td>跳到行尾</td><td>✅</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>K</kbd></td><td>删除光标到行尾</td><td>✅</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>U</kbd></td><td>删除光标到行首</td><td>✅</td></tr><tr><td><kbd>Ctrl</kbd>+<kbd>W</kbd></td><td>删除上一个单词</td><td>✅</td></tr><tr><td><kbd>Alt</kbd>+<kbd>B</kbd></td><td>后退一个单词</td><td>✅</td></tr><tr><td><kbd>Alt</kbd>+<kbd>F</kbd></td><td>前进一个单词</td><td>✅</td></tr></tbody></table><details class="details custom-block"><summary>📦 什么是 Readline 风格？</summary><p>Readline 是 Unix/Linux 终端的标准输入库，定义了一套通用的快捷键。</p><p>几乎所有终端程序（bash、zsh、python REPL）都支持这套快捷键。如果你天天在终端工作，这些快捷键已经是肌肉记忆了。</p><p>OpenCode 完全兼容 Readline，让你在输入框里也能用熟悉的方式编辑文本。</p></details><hr><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to “跟我做”">​</a></h2><h3 id="第-1-步-练习换行输入" tabindex="-1">第 1 步：练习换行输入 <a class="header-anchor" href="#第-1-步-练习换行输入" aria-label="Permalink to “第 1 步：练习换行输入”">​</a></h3><p><strong>为什么</strong><br> 写多行提示词时，你需要换行而不是发送。</p><ol><li>在输入框输入 <code>第一行</code></li><li>按 <kbd>Shift</kbd>+<kbd>Enter</kbd></li><li>输入 <code>第二行</code></li></ol><p><strong>你应该看到</strong>：输入框中有两行文字，消息没有发送</p><div class="warning custom-block"><p class="custom-block-title">⚠️ 常见问题</p><p>如果按 <kbd>Shift</kbd>+<kbd>Enter</kbd> 不换行，直接发送了消息，说明你的终端不支持修饰键。解决方案：</p><ul><li>改用 <kbd>Ctrl</kbd>+<kbd>J</kbd>（更通用）</li><li>或参考 <a href="./../5-advanced/06b-keybinds.html#终端兼容性">5.6b 快捷键</a> 配置终端</li></ul></div><h3 id="第-2-步-练习历史记录" tabindex="-1">第 2 步：练习历史记录 <a class="header-anchor" href="#第-2-步-练习历史记录" aria-label="Permalink to “第 2 步：练习历史记录”">​</a></h3><p><strong>为什么</strong><br> 想重新发送或修改之前的消息，不用重新打字。</p><ol><li>先发送一条消息：<code>你好</code></li><li>等 AI 回复后，确保输入框是空的</li><li>按 <kbd>↑</kbd>（上箭头）</li></ol><p><strong>你应该看到</strong>：输入框自动填入了你刚才发送的 <code>你好</code></p><p>继续按 <kbd>↑</kbd> 可以翻阅更早的历史记录，按 <kbd>↓</kbd> 回到更近的。</p><h3 id="第-3-步-练习-ctrl-c" tabindex="-1">第 3 步：练习 Ctrl+C <a class="header-anchor" href="#第-3-步-练习-ctrl-c" aria-label="Permalink to “第 3 步：练习 Ctrl+C”">​</a></h3><p><strong>为什么</strong><br> 快速清空输入、关闭对话框，或退出 OpenCode。</p><p><strong>场景 A - 清空输入</strong>：</p><ol><li>在输入框输入一些文字</li><li>按 <kbd>Ctrl</kbd>+<kbd>C</kbd></li></ol><p><strong>你应该看到</strong>：输入框被清空</p><p><strong>场景 B - 关闭对话框</strong>：</p><ol><li>触发一个对话框（如按 <kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>L</kbd> 打开会话列表）</li><li>按 <kbd>Ctrl</kbd>+<kbd>C</kbd></li></ol><p><strong>你应该看到</strong>：对话框关闭，返回正常对话界面</p><p><strong>场景 C - 退出应用</strong>：</p><ol><li>确保输入框是空的，且没有弹出对话框</li><li>按 <kbd>Ctrl</kbd>+<kbd>C</kbd></li></ol><p><strong>你应该看到</strong>：OpenCode 退出</p><h3 id="第-4-步-练习-leader-键组合" tabindex="-1">第 4 步：练习 Leader 键组合 <a class="header-anchor" href="#第-4-步-练习-leader-键组合" aria-label="Permalink to “第 4 步：练习 Leader 键组合”">​</a></h3><p><strong>为什么</strong><br> 这是 OpenCode 最核心的快捷键机制。</p><p><strong>重要</strong>：这是两步操作，不是同时按！</p><ol><li>按下 <kbd>Ctrl</kbd>+<kbd>X</kbd></li><li><strong>松开所有键</strong>（这一步很关键！）</li><li>按下 <kbd>N</kbd></li></ol><p><strong>你应该看到</strong>：创建了一个新会话</p><p>再试试打开会话列表：</p><ol><li>按下 <kbd>Ctrl</kbd>+<kbd>X</kbd></li><li><strong>松开</strong></li><li>按下 <kbd>L</kbd></li></ol><p><strong>你应该看到</strong>：弹出会话列表</p><h3 id="第-5-步-练习撤销重做" tabindex="-1">第 5 步：练习撤销重做 <a class="header-anchor" href="#第-5-步-练习撤销重做" aria-label="Permalink to “第 5 步：练习撤销重做”">​</a></h3><p><strong>为什么</strong><br> AI 回复不满意时可以重来。</p><ol><li>发送一条消息给 AI</li><li>等 AI 回复后，按 <kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>U</kbd></li></ol><p><strong>你应该看到</strong>：刚才的消息和回复被撤销了</p><p>再按 <kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>R</kbd> 可以重做。</p><h3 id="第-6-步-练习中断响应" tabindex="-1">第 6 步：练习中断响应 <a class="header-anchor" href="#第-6-步-练习中断响应" aria-label="Permalink to “第 6 步：练习中断响应”">​</a></h3><p><strong>为什么</strong><br> AI 回复太长或方向错误时及时止损。</p><ol><li>发送一个复杂问题</li><li>在 AI 回复过程中按 <kbd>Escape</kbd></li></ol><p><strong>你应该看到</strong>：AI 停止生成</p><hr><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to “检查点 ✅”">​</a></h2><blockquote><p>全部通过才能继续</p></blockquote><ul><li>[ ] <kbd>Shift</kbd>+<kbd>Enter</kbd> 能换行而不发送</li><li>[ ] <kbd>↑</kbd> 能翻阅历史输入（输入框为空时）</li><li>[ ] <kbd>Ctrl</kbd>+<kbd>C</kbd> 能清空输入、关闭对话框</li><li>[ ] <kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>N</kbd> 能新建会话（注意要松开再按 N）</li><li>[ ] <kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>L</kbd> 能打开会话列表</li><li>[ ] <kbd>Escape</kbd> 能中断 AI 响应</li></ul><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to “踩坑提醒”">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>原因</th><th>解决</th></tr></thead><tbody><tr><td>Shift+Enter 不换行，直接发送</td><td>终端不发送修饰键</td><td>改用 <kbd>Ctrl</kbd>+<kbd>J</kbd>，或配置终端</td></tr><tr><td>按 Ctrl+X 然后按 N 没反应</td><td>没有松开 Ctrl+X 就按了 N</td><td><strong>必须先松开</strong>，再按 N</td></tr><tr><td>按 Ctrl+X 没反应</td><td>终端劫持了该按键</td><td>检查终端设置，或换个终端</td></tr><tr><td><strong>Ctrl+C 不是复制</strong></td><td>用来清空输入或退出，不是复制</td><td>要复制请用 <kbd>Ctrl</kbd>+<kbd>X</kbd> → <kbd>Y</kbd> 或鼠标选中后 <kbd>Ctrl</kbd>+<kbd>V</kbd></td></tr><tr><td>上箭头没有出现历史记录</td><td>输入框不是空的</td><td>先清空输入框（Ctrl+C），再按上箭头</td></tr><tr><td>Tab 没有切换 Agent</td><td>在输入状态按的</td><td>先按 Escape 退出输入，再按 Tab</td></tr><tr><td><strong>Ctrl+Z 意外挂起</strong></td><td>以为是撤销，实际是挂起终端</td><td>OpenCode 会暂停，需在终端输入 <code>fg</code> 恢复。不要用来&quot;撤销&quot;！</td></tr></tbody></table><hr><h2 id="快捷键速记口诀" tabindex="-1">快捷键速记口诀 <a class="header-anchor" href="#快捷键速记口诀" aria-label="Permalink to “快捷键速记口诀”">​</a></h2>',64)),t[4]||(t[4]=d("div",{class:"language-"},[d("button",{title:"Copy Code",class:"copy"}),d("span",{class:"lang"}),d("pre",null,[d("code",{"v-pre":""},`回车发送，Shift 换行
上箭头翻历史，Ctrl+C 关弹框清输入
新建 N，列表 L，模型 M 要牢记
撤销 U，重做 R，复制 Y 不费力
Escape 中断响应快
Tab 切 Agent 真方便
Ctrl+Z 会挂起，别当撤销用`)])],-1)),t[5]||(t[5]=r('<hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to “本课小结”">​</a></h2><p>你学会了：</p><ol><li><strong>换行技巧</strong>：<kbd>Shift</kbd>+<kbd>Enter</kbd> 换行，<kbd>Enter</kbd> 发送</li><li><strong>历史记录</strong>：输入框为空时，<kbd>↑</kbd>/<kbd>↓</kbd> 翻阅历史</li><li><strong>Ctrl+C</strong>：关闭对话框 / 清空输入（有内容）或退出（无内容）</li><li><strong>Leader 键机制</strong>：<kbd>Ctrl</kbd>+<kbd>X</kbd> → 松开 → 字母键</li><li><strong>会话管理</strong>：N（新建）、L（列表）、U（撤销）</li><li><strong>程序员福利</strong>：Readline 风格快捷键全兼容</li></ol><hr><h2 id="想要更多" tabindex="-1">想要更多？ <a class="header-anchor" href="#想要更多" aria-label="Permalink to “想要更多？”">​</a></h2><ul><li><a href="./../appendix/keybinds.html">速查/快捷键速查表</a> - 完整 60+ 快捷键列表</li><li><a href="./../5-advanced/06b-keybinds.html">5.6b 快捷键</a> - 自定义快捷键教程</li></ul><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to “下一课预告”">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./04-global-rules.html">全局提示词</a></strong>，让 AI 永久记住你的工作习惯。</p><p>你会学到：</p><ul><li>创建规则文件，不用每次都说&quot;用中文回复&quot;</li><li>全局规则 vs 项目规则的区别</li><li>实用规则示例</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to “附录：源码参考”">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-13</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>快捷键默认值</td><td><a href="https://github.com/anomalyco/opencode/blob/dev/packages/opencode/src/config/config.ts#L616-L754" target="_blank" rel="noreferrer"><code>src/config/config.ts</code></a></td><td>616-754</td></tr><tr><td>快捷键解析</td><td><a href="https://github.com/anomalyco/opencode/blob/dev/packages/opencode/src/util/keybind.ts" target="_blank" rel="noreferrer"><code>src/util/keybind.ts</code></a></td><td>全文件</td></tr></tbody></table><p><strong>关键默认值</strong>（来自 <code>config.ts</code>）：</p><ul><li><code>input_submit = &quot;return&quot;</code> - 发送消息（第 668 行）</li><li><code>input_newline = &quot;shift+return,ctrl+return,alt+return,ctrl+j&quot;</code> - 换行（第 669-673 行）</li><li><code>input_clear = &quot;ctrl+c&quot;</code> - 清空输入（第 666 行）</li><li><code>app_exit = &quot;ctrl+c,ctrl+d,&lt;leader&gt;q&quot;</code> - 退出应用（第 617 行）</li><li><code>history_previous = &quot;up&quot;</code> - 上一条历史（第 747 行）</li><li><code>history_next = &quot;down&quot;</code> - 下一条历史（第 748 行）</li><li><code>agent_cycle = &quot;tab&quot;</code> - 切换 Agent（第 663 行）</li><li><code>leader = &quot;ctrl+x&quot;</code> - Leader 键（第 616 行）</li><li><code>session_new = &quot;&lt;leader&gt;n&quot;</code> - 新建会话</li><li><code>session_list = &quot;&lt;leader&gt;l&quot;</code> - 会话列表</li><li><code>model_list = &quot;&lt;leader&gt;m&quot;</code> - 模型列表</li><li><code>messages_undo = &quot;&lt;leader&gt;u&quot;</code> - 撤销消息</li><li><code>messages_redo = &quot;&lt;leader&gt;r&quot;</code> - 重做消息</li></ul></details>',13))])}const _=e(s,[["render",k]]);export{m as __pageData,_ as default};
